    const enrichBtn = isGroup ? `<button class="gridLinkBtn" type="button" data-resolve-group="${escH(String(abs))}" data-resolve-full="1"><span class="gridLinkIcon">${enrichIcon}</span> ${enrichText}</button>` : `<button class="gridLinkBtn" type="button" data-resolve-user="${escH(String(abs))}" data-resolve-full="1"><span class="gridLinkIcon">${enrichIcon}</span> ${enrichText}</button>`;
